/**
* Completions offered at the dollar position: `$|`
*/
async function dollarCompletions(context) {
	const word = context.matchBefore(/\$[^$]*/);
	if (!word) return null;
	if (word.from === word.to && !context.explicit) return null;
	let options = (await dollarOptions(context)).map(stripExcessParens(context));
	const userInput = word.text;
	if (userInput !== "$") options = options.filter((o) => prefixMatch(o.label, userInput));
	if (options.length === 0) return null;
	return {
		from: word.to - userInput.length,
		options,
		filter: false,
		getMatch(completion) {
			return [0, longestCommonPrefix(userInput, completion.label).length];
		}
	};
}
