//#region src/features/shared/editors/plugins/codemirror/completions/blank.completions.ts
/**
* Completions offered at the blank position: `{{ | }}`
*/
async function blankCompletions(context) {
	const word = context.matchBefore(/\{\{\s/);
	if (!word) return null;
	if (word.from === word.to && !context.explicit) return null;
	if (context.state.sliceDoc(context.pos, context.pos + 3) !== " }}") return null;
	return {
		from: word.to,
		options: (await dollarOptions(context)).map(stripExcessParens(context)),
		filter: false
	};
}
//#endregion
//#region src/features/shared/editors/plugins/codemirror/completions/bracketAccess.completions.ts
/**
* Resolution-based completions offered at the start of bracket access notation.
*
* - `$json[|`
* - `$input.item.json[|`
* - `$json['field'][|`
* - `$json.myObj[|`
* - `$('Test').last().json.myArr[|`
* - `$input.first().json.myStr[|`
*/
async function bracketAccessCompletions(context) {
	const targetNodeParameterContext = context.state.facet(TARGET_NODE_PARAMETER_FACET);
	const workflowDocumentId = context.state.facet(WORKFLOW_DOCUMENT_FACET);
	if (!workflowDocumentId) return null;
	const word = context.matchBefore(/\$[\S\s]*\[.*/);
	if (!word) return null;
	if (word.from === word.to && !context.explicit) return null;
	if ([
		"$input[",
		"$now[",
		"$today["
	].includes(word.text)) return null;
	const base = word.text.substring(0, word.text.lastIndexOf("["));
	const tail = word.text.split("[").pop() ?? "";
	let resolved;
	try {
		resolved = await resolveAutocompleteExpression(`={{ ${base} }}`, workflowDocumentId, targetNodeParameterContext?.nodeName);
	} catch {
		return null;
	}
	if (resolved === null || resolved === void 0 || typeof resolved !== "object") return null;
	let options = bracketAccessOptions(resolved);
	if (tail !== "") options = options.filter((o) => prefixMatch(o.label, tail));
	if (options.length === 0) return null;
	return {
		from: word.to - tail.length,
		options,
		filter: false,
		getMatch(completion) {
			return [0, longestCommonPrefix(tail, completion.label).length];
		}
	};
}
function bracketAccessOptions(resolved) {
	const SKIP = new Set(["__ob__", "pairedItem"]);
	return Object.keys(resolved).filter((key) => !SKIP.has(key)).map((key) => {
		return {
			label: !isNaN(parseInt(key)) ? `${key}]` : `'${escapeMappingString(key)}']`,
			type: "keyword"
		};
	});
}
