var DATATYPE_REGEX = new RegExp(Object.values({
	generalRef: /\$[^$'"]+\.(.*)/,
	selectorRef: /\$\(['"][\S\s]+['"]\)\??\.(.*)/,
	numberLiteral: /\((\d+)\.?(\d*)\)\.(.*)/,
	singleQuoteStringLiteral: /('.*')\.([^'{\s])*/,
	booleanLiteral: /(true|false)\.([^'{\s])*/,
	doubleQuoteStringLiteral: /(".*")\.([^"{\s])*/,
	dateLiteral: /\(?new Date\(\(?.*?\)\)?\.(.*)/,
	arrayLiteral: /\(?(\[.*\])\)?\.(.*)/,
	indexedAccess: /([^"{\s]+\[.+\])\??\.(.*)/,
	objectLiteral: /\(\{.*\}\)\.(.*)/,
	mathGlobal: /Math\.(.*)/,
	datetimeGlobal: /DateTime\.(.*)/,
	objectGlobal: /Object\.(.*)/
}).map((regex) => regex.source).join("|"));
