//#region src/features/shared/editors/plugins/codemirror/completions/addCompletions.ts
function n8nCompletionSources() {
	return [
		blankCompletions,
		bracketAccessCompletions,
		datatypeCompletions,
		dollarCompletions,
		nonDollarCompletions
	].map((source) => ({ autocomplete: ifIn(["Resolvable"], source) }));
}
